package main
import ("bufio";"fmt";"os";"regexp";"sort";"strings";"time")
type Rec struct { User string; IPs map[string]bool; Last string }
func main(){ f,err:=os.Open("/var/log/xray/access.log"); if err!=nil { fmt.Println("cannot open access log"); return }; defer f.Close(); re:=regexp.MustCompile(`tcp:([0-9]+\.[0-9]+\.[0-9]+\.[0-9]+):[0-9]+.*email: ([^ ]+)`); now:=time.Now().Format("15:04:05"); data:=map[string]*Rec{}; s:=bufio.NewScanner(f); for s.Scan(){ line:=s.Text(); if !strings.Contains(line,"email: "){ continue }; m:=re.FindStringSubmatch(line); if len(m)<3 { continue }; ip,user:=m[1],strings.TrimSpace(m[2]); if _,ok:=data[user]; !ok { data[user]=&Rec{User:user,IPs:map[string]bool{}} }; data[user].IPs[ip]=true; data[user].Last=now }; keys:=make([]string,0,len(data)); for k:=range data { keys=append(keys,k) }; sort.Strings(keys); fmt.Println("ONLINE USER"); fmt.Println("━━━━━━━━━━━━━━━━━━━━━━━━━━━━"); for _,k:=range keys { v:=data[k]; ips:=make([]string,0,len(v.IPs)); for ip:=range v.IPs { ips=append(ips,ip) }; sort.Strings(ips); fmt.Printf(" User        : %s\n Last Login  : %s\n Online IP   : %d\n IP Address  : %s\n────────────────────────────\n", v.User,v.Last,len(ips),strings.Join(ips,", ")) } }
